-- QA custom-forms 500 fix — refresh the 5 seeded form templates.
--
-- The Custom Forms module POSTs each picked template's `template_json`
-- verbatim to Dmytro's
--   POST /onboarding-app/custom-form-template/import-json
-- (see lib/clients/fp-api/endpoints/forms.ts). The templates seeded by
-- migration 013 were missing the top-level `formulas` array; FP dereferences
-- it server-side, so every custom-forms import returned HTTP 500 (reproducible
-- for every form, on every submit where FP_CUSTOM_FORMS_ENABLED=true).
--
-- This migration replaces all 5 template_json blobs with FP's corrected
-- exports: each adds `"formulas": []`, widens view_by_role_permission to
-- [1,2,4,5], plus minor field fixes. The inlined blobs are verbatim copies of
-- the updated supabase/seed/form-templates/*.json files (kept in sync for
-- diffability, matching migration 013's convention).
--
-- Idempotent: plain UPDATE keyed on the unique `name`; safe to re-run.

update form_template_library
set    template_json = $json$
